'use client';

import { useState } from 'react';
import { calculateTax, formatPKR, TaxInput, TaxResult } from '../lib/taxEngine';

interface Message {
  role: 'user' | 'assistant';
  content: string;
  result?: TaxResult | null;
}

export default function ChatBot() {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMessage: Message = { role: 'user', content: input };
    const newMessages = [...messages, userMessage];
    setMessages(newMessages);
    setInput('');
    setIsLoading(true);

    try {
      const res = await fetch('/api/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ messages: newMessages }),
      });

      if (!res.ok) {
        throw new Error('API call failed');
      }

      const data = await res.json();
      let assistantContent = data.content;
      let taxResult: TaxResult | null = null;

      const calculatePrefix = 'CALCULATE:';
      if (assistantContent.includes(calculatePrefix)) {
        const parts = assistantContent.split(calculatePrefix);
        assistantContent = parts[0]; // The text part before the tag
        const jsonPart = parts[1];
        try {
          const aiInput = JSON.parse(jsonPart);
          const mappedInput: TaxInput = {
              taxpayerType: aiInput.type,
              taxYear: aiInput.year,
              filerStatus: aiInput.filerStatus,
              isOverseas: aiInput.isOverseas,
              salary: aiInput.salary,
              businessRevenue: aiInput.businessRevenue,
              businessExpenses: aiInput.businessExpenses,
              rentalIncome: aiInput.rentalIncome,
              freelanceIncome: aiInput.freelanceIncome,
              capitalGains: aiInput.capitalGains,
              otherIncome: aiInput.otherIncome,
              zakat: aiInput.zakat,
              pensionContribution: aiInput.pension,
              lifeInsurance: aiInput.lifeInsurance,
              donations: aiInput.donations,
              whtSalary: aiInput.whtSalary,
              whtBank: aiInput.whtBank,
              whtMobile: aiInput.whtMobile,
              whtProperty: aiInput.whtProperty,
              whtOther: aiInput.whtOther,
          };
          taxResult = calculateTax(mappedInput);
          assistantContent += `\n\nHere is your tax calculation summary:`;
        } catch (e) {
          console.error('Failed to parse tax calculation JSON:', e);
          assistantContent += "\n\n[Error: I tried to calculate the tax but the data was in the wrong format.]";
        }
      }
      
      const assistantMessage: Message = { role: 'assistant', content: assistantContent, result: taxResult };
      setMessages(prev => [...prev, assistantMessage]);

    } catch (error) {
      const errorMessage: Message = { role: 'assistant', content: 'Sorry, something went wrong. Please try again.' };
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div style={{ fontFamily: 'sans-serif', maxWidth: '600px', margin: 'auto', padding: '20px' }}>
      <div style={{ border: '1px solid #ccc', borderRadius: '8px', height: '400px', overflowY: 'auto', padding: '10px', marginBottom: '10px', display: 'flex', flexDirection: 'column' }}>
        {messages.map((msg, i) => (
          <div key={i} style={{ alignSelf: msg.role === 'user' ? 'flex-end' : 'flex-start', background: msg.role === 'user' ? '#dcf8c6' : '#f1f0f0', borderRadius: '10px', padding: '8px 12px', marginBottom: '8px', maxWidth: '80%' }}>
            <strong style={{ display: 'block', marginBottom: '4px' }}>{msg.role === 'user' ? 'You' : 'TaxBot'}</strong>
            <p style={{ margin: 0, whiteSpace: 'pre-wrap' }}>{msg.content}</p>
            {msg.result && (
              <div style={{ marginTop: '10px', borderTop: '1px solid #ddd', paddingTop: '10px' }}>
                <h4>Tax Calculation Result (2024-2025)</h4>
                <p><strong>Gross Tax:</strong> {formatPKR(msg.result.grossTax)}</p>
                <p><strong>Total WHT Paid:</strong> {formatPKR(msg.result.totalWHTPaid)}</p>
                <p style={{ fontWeight: 'bold', color: msg.result.isRefund ? 'green' : 'red' }}>
                  <strong>{msg.result.isRefund ? 'Refund Due:' : 'Net Payable:'}</strong> {formatPKR(msg.result.netPayable)}
                </p>
                 <p><strong>Slab:</strong> {msg.result.currentSlab}</p>
              </div>
            )}
          </div>
        ))}
         {isLoading && <div style={{ alignSelf: 'flex-start' }}><em>TaxBot is typing...</em></div>}
      </div>
      <div style={{ display: 'flex' }}>
        <input
          type="text"
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyPress={e => e.key === 'Enter' && handleSend()}
          style={{ flexGrow: 1, padding: '10px', borderRadius: '5px', border: '1px solid #ccc' }}
          placeholder="Aapka sawaal..."
          disabled={isLoading}
        />
        <button onClick={handleSend} style={{ padding: '10px 15px', marginLeft: '10px', borderRadius: '5px', border: 'none', background: '#007bff', color: 'white', cursor: 'pointer' }} disabled={isLoading}>
          Send
        </button>
      </div>
    </div>
  );
}
